import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const API = 'http://localhost:5000';

// Constructors in the order you want them in the dropdown
const CONSTRUCTOR_ORDER = [
  'McLaren',
  'Ferrari',
  'Red Bull',
  'Mercedes',
  'Aston Martin',
  'Alpine',
  'Williams',
  'Racing Bulls',
  'Haas',
  'Audi',
  'Cadillac',
];

// Constructor brand colors for pill badges
const CONSTRUCTOR_COLORS = {
  'McLaren':       '#FF8000',
  'Ferrari':       '#DC0000',
  'Red Bull':      '#3671C6',
  'Mercedes':      '#27F4D2',
  'Aston Martin':  '#358C75',
  'Alpine':        '#FF87BC',
  'Williams':      '#64C4FF',
  'Racing Bulls':  '#6692FF',
  'Haas':          '#B6BABD',
  'Audi':          '#C0C0C0',
  'Cadillac':      '#BA0E2B',
};

function App() {
  const [grid, setGrid] = useState([]);          // all 22 drivers from API
  const [circuits, setCircuits] = useState([]);
  const [selectedCircuit, setSelectedCircuit] = useState('');
  // gridPositions: { slotIndex (1-22): driver_id | '' }
  const [gridPositions, setGridPositions] = useState({});
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Sort drivers by constructor order, then name
  const sortedDriversList = React.useMemo(() => {
    if (!grid.length) return [];
    return [...grid].sort((a, b) => {
      const ai = CONSTRUCTOR_ORDER.indexOf(a.constructor_name);
      const bi = CONSTRUCTOR_ORDER.indexOf(b.constructor_name);
      const orderA = ai === -1 ? 99 : ai;
      const orderB = bi === -1 ? 99 : bi;
      if (orderA !== orderB) return orderA - orderB;
      return a.driver_name.localeCompare(b.driver_name);
    });
  }, [grid]);

  // Load driver grid and circuits on mount
  useEffect(() => {
    const loadData = async () => {
      try {
        const [gridRes, circuitRes] = await Promise.all([
          axios.get(`${API}/api/grid-info`),
          axios.get(`${API}/api/circuits`)
        ]);

        setGrid(gridRes.data);
        setCircuits(circuitRes.data);

        // Initialize 22 grid slots, all empty
        const initial = {};
        for (let i = 1; i <= 22; i++) initial[i] = '';
        setGridPositions(initial);

        if (circuitRes.data.length > 0) {
          setSelectedCircuit(circuitRes.data[0].id.toString());
        }
      } catch (err) {
        setError('Failed to load data from server. Is the backend running?');
        console.error(err);
      }
    };
    loadData();
  }, []);

  // Which driver IDs are already assigned to a slot
  const assignedDriverIds = React.useMemo(() => {
    return new Set(Object.values(gridPositions).filter(v => v !== '').map(Number));
  }, [gridPositions]);

  const handleSlotChange = (slot, driverId) => {
    setGridPositions(prev => {
      const updated = { ...prev };
      // If this driver is already somewhere else, clear that slot
      Object.keys(updated).forEach(s => {
        if (updated[s] === driverId && Number(s) !== slot) updated[s] = '';
      });
      updated[slot] = driverId;
      return updated;
    });
  };

  const validateGridPositions = () => {
    const filled = Object.values(gridPositions).filter(v => v !== '');
    if (filled.length !== 22) {
      setError(`Please assign a driver to all 22 grid positions (${filled.length}/22 done)`);
      return false;
    }
    return true;
  };

  const handlePredictAll = async () => {
    setError(null);
    if (!selectedCircuit) { setError('Please select a circuit'); return; }
    if (!validateGridPositions()) return;

    setLoading(true);
    setResults(null);

    // Build payload: { driver_id: grid_slot }
    const grid_positions_payload = {};
    Object.entries(gridPositions).forEach(([slot, driverId]) => {
      if (driverId !== '') grid_positions_payload[driverId] = parseInt(slot);
    });

    try {
      const response = await axios.post(`${API}/api/predict-batch`, {
        circuit_id: parseInt(selectedCircuit),
        grid_positions: grid_positions_payload
      });

      const sorted = response.data.predictions.sort((a, b) => b.ensemble_prob - a.ensemble_prob);
      setResults(sorted);
    } catch (err) {
      setError(err.response?.data?.error || 'Batch prediction failed: ' + err.message);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResults(null);
    const initial = {};
    for (let i = 1; i <= 22; i++) initial[i] = '';
    setGridPositions(initial);
    setError(null);
  };

  // How many slots filled
  const filledCount = Object.values(gridPositions).filter(v => v !== '').length;

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-inner">
          <span className="f1-logo">F1</span>
          <div>
            <h1>Podium Predictor</h1>
            <p>Set the starting grid · Run the model · See who makes the podium</p>
          </div>
        </div>
      </header>

      <div className="container">

        {/* Circuit Selector */}
        <div className="circuit-selector">
          <label htmlFor="circuit">Circuit</label>
          <select
            id="circuit"
            value={selectedCircuit}
            onChange={(e) => setSelectedCircuit(e.target.value)}
            className="circuit-dropdown"
          >
            <option value="">— Choose Circuit —</option>
            {circuits.map(circ => (
              <option key={circ.id} value={circ.id}>
                {circ.name} · {circ.location}
              </option>
            ))}
          </select>
          <div className="fill-counter">
            <span className={filledCount === 22 ? 'counter-full' : ''}>{filledCount}</span>/22 drivers placed
          </div>
        </div>

        {/* Starting Grid — Eagle View */}
        {!results && (
          <div className="grid-section">
            <div className="grid-section-header">
              <h2>Starting Grid</h2>
              <p>Assign a driver to each grid position. P1 is pole, P22 is the back.</p>
            </div>

            {/* Track surface */}
            <div className="track-surface">
              {/* Finish / Pole line label */}
              <div className="track-pole-label">◀ POLE POSITION — P1</div>

              <div className="grid-slots">
                {/* Render P22 down to P1 visually (P1 at bottom = front of grid) */}
                {Array.from({ length: 22 }, (_, i) => {
                  const pos = 22 - i; // 22, 21, ..., 1
                  const isLeft = pos % 2 === 0;  // even = left side
                  const driverId = gridPositions[pos] || '';
                  const driverObj = driverId ? grid.find(d => d.driver_id === Number(driverId)) : null;
                  const conColor = driverObj ? (CONSTRUCTOR_COLORS[driverObj.constructor_name] || '#888') : null;

                  return (
                    <div
                      key={pos}
                      className={`grid-slot ${isLeft ? 'slot-left' : 'slot-right'} ${driverId ? 'slot-filled' : ''}`}
                      style={driverId ? { '--accent': conColor } : {}}
                    >
                      <div className="slot-pos-number">P{pos}</div>

                      <div className="slot-car">
                        {driverId && (
                          <div className="slot-car-body" style={{ background: conColor }} />
                        )}
                        {!driverId && <div className="slot-car-empty" />}
                      </div>

                      <div className="slot-dropdown-wrap">
                        <select
                          className="slot-driver-select"
                          value={driverId}
                          onChange={(e) => handleSlotChange(pos, e.target.value)}
                          style={driverId ? { borderColor: conColor, color: '#fff' } : {}}
                        >
                          <option value="">— Pick driver —</option>
                          {/* Group by constructor */}
                          {CONSTRUCTOR_ORDER.map(constructor => {
                            const driversInTeam = sortedDriversList.filter(d => d.constructor_name === constructor);
                            if (!driversInTeam.length) return null;
                            return (
                              <optgroup key={constructor} label={constructor}>
                                {driversInTeam.map(d => (
                                  <option
                                    key={d.driver_id}
                                    value={d.driver_id}
                                    disabled={assignedDriverIds.has(d.driver_id) && String(d.driver_id) !== String(driverId)}
                                  >
                                    {d.driver_name}
                                    {assignedDriverIds.has(d.driver_id) && String(d.driver_id) !== String(driverId) ? ' ✓' : ''}
                                  </option>
                                ))}
                              </optgroup>
                            );
                          })}
                        </select>

                        {driverObj && (
                          <div className="slot-team-pill" style={{ background: conColor }}>
                            {driverObj.constructor_name}
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>

              <div className="track-back-label">P22 — BACK OF GRID ▶</div>
            </div>

            {error && <div className="error-box">{error}</div>}

            <button
              onClick={handlePredictAll}
              disabled={loading || filledCount < 22}
              className="predict-btn"
            >
              {loading ? 'Running Models…' : `Predict Podium${filledCount < 22 ? ` (${filledCount}/22)` : ''}`}
            </button>
          </div>
        )}

        {/* Results Panel */}
        {results && (
          <div className="results-panel">
            <h2>Podium Predictions</h2>
            <table className="results-table">
              <thead>
                <tr>
                  <th>Rank</th>
                  <th>Driver</th>
                  <th>Constructor</th>
                  <th>Grid</th>
                  <th>RF %</th>
                  <th>CB %</th>
                  <th>Ensemble %</th>
                  <th>Verdict</th>
                </tr>
              </thead>
              <tbody>
                {results.map((result, idx) => (
                  <tr key={result.driver_id} className={result.prediction === 'PODIUM' ? 'podium-row' : ''}>
                    <td className="rank">#{idx + 1}</td>
                    <td className="driver-name">{result.driver_name}</td>
                    <td className="constructor">
                      <span className="team-dot" style={{ background: CONSTRUCTOR_COLORS[result.constructor_name] || '#888' }} />
                      {result.constructor_name}
                    </td>
                    <td className="grid-pos">P{result.grid}</td>
                    <td className="probability">{result.rf_prob.toFixed(1)}%</td>
                    <td className="probability">{result.cb_prob.toFixed(1)}%</td>
                    <td className="probability ensemble">{result.ensemble_prob.toFixed(1)}%</td>
                    <td className={`verdict ${result.prediction === 'PODIUM' ? 'podium' : 'no-podium'}`}>
                      {result.prediction}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            <button onClick={handleReset} className="reset-btn">
              ← Reset Grid
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
